     if ((msg.payload.data != undefined) && (msg.payload.data.dps != undefined) && (msg.payload.data.dps[triggerDP] < 800))
        return null;
    var n = env.get("TRGnumber");
    var trig = {
           "payload": {
              "dps":triggerDP, 
              "set": parseInt(n)       
              }
    }

    return trig ;
} catch(e) {
    node.error("Error in send  X TRIGGER: " + e.message, msg);
    return null;
}

