let aIndex = -1, kIndex = -1
let lines = msg.payload.split('\n')

for (let i = lines.length - 1; i >= 0; i--) {
    let line = lines[i].trim()
    if (!line || line.startsWith('#') || line.startsWith(':')) continue
    let cols = line.split(/\s+/)
    // Data line: YYYY MM DD | mid-lat A + 8 K | high-lat A + 8 K | planetary A + 8 K
    // Planetary A is cols[21], planetary K values are cols[22]-cols[29]
    if (cols.length < 30) continue
    let ap = parseInt(cols[21])
    if (isNaN(ap) || ap < 0) continue
    aIndex = ap
    // Last valid planetary Kp (cols 22-29, fractional 0.00-9.00)
    for (let j = 29; j >= 22; j--) {
        let kv = parseFloat(cols[j])
        if (!isNaN(kv) && kv >= 0 && kv <= 9) {
            kIndex = kv
            break
        }
    }
    break
}

