    grid_square:   flow.get('grid_square')  || '—',
    threshold_km:  isNaN(thr) ? 20 : thr,
    reconnect_min: isNaN(rec) ? 5  : rec,
    total:    st.total,
    near:     st.near,
    mid:      st.mid,
    far:      st.far,
    closest:  st.closest,
    antenna_off:   off,
    radio_off:     roff,
    radio_enabled: flow.get('radio_enabled') || false,
    radio_label:   flow.get('radio_label')   || 'Radio'
};
return msg;

// Unified strike → dashboard handler.
// Fed by:
//   - Haversine Distance (Open-Meteo + TEST inject path)
//   - AS3935 Threshold Check (AS3935 sensor path)
// Both upstream nodes set msg.strike with lat/lon/distance_km/time/source.
// AS3935 Threshold Check additionally sets msg.strike.energy.

const km = msg.strike.distance_km;
const thr = flow.get('threshold_km') || 20;
const ren = flow.get('radio_enabled') || false;
const rlbl = flow.get('radio_label') || 'Radio';
const isAS3935 = (msg.strike.source || '').toLowerCase().indexOf('as3935') !== -1;

const payload = {
    type: 'strike',
    lat: msg.strike.lat,
    lon: msg.strike.lon,
    km: km,
    time: msg.strike.time,
    color: km <= thr ? '#f85149' : km <= 50 ? '#e3b341' : '#FFEE00',
    offLabel: ren ? 'ANTENNA + ' + rlbl + ' OFF' : 'ANTENNA OFF',
    homeLat: flow.get('home_lat'),
    homeLon: flow.get('home_lon'),
    thrKm: thr,
    callsign: flow.get('callsign') || '',
    gs: flow.get('grid_square') || ''
};
if (isAS3935) {
    payload.source = 'as3935';
    payload.energy = msg.strike.energy || 0;
}
msg.payload = payload;
return msg;

const log = flow.get('event_log') || [];
msg.payload = { type: 'log', html: log.join('') };
return msg;

const off = flow.get('antenna_off') || false;
msg.payload = { switch_state: off ? 'false' : 'true' };
return msg;

// Payload from Python bridge: {event, distance, energy, timestamp}
const p = msg.payload;
const evt = (p.event || '').toLowerCase();

if (evt === 'lightning') {
    const dist   = parseInt(p.distance) || 0;
    const energy = parseInt(p.energy)   || 0;
    // AS3935 reports 1 = overhead, 40 = out of range
    const dist_km = (dist === 63) ? null : dist;   // 63 = out-of-range
    msg.source    = 'as3935';
    msg.as3935    = { event: 'lightning', distance_km: dist_km, energy: energy, timestamp: p.timestamp };
    msg.payload   = msg.as3935;
    node.status({fill:'red', shape:'dot',
        text: dist_km === null ? '⚡ Out of range' : '⚡ '+dist_km+' km  energy='+energy});
    return [msg, null, null];

} else if (evt === 'disturber') {
    msg.source  = 'as3935';
    msg.as3935  = { event: 'disturber', timestamp: p.timestamp };
    msg.payload = msg.as3935;
    node.status({fill:'yellow', shape:'ring', text:'⚠ Disturber'});
    return [null, msg, null];

} else if (evt === 'noise') {
    msg.source  = 'as3935';
    msg.as3935  = { event: 'noise', timestamp: p.timestamp };
    msg.payload = msg.as3935;
    node.status({fill:'grey', shape:'ring', text:'📡 Noise'});
    return [null, null, msg];
}
return null;

const thr = flow.get('threshold_km') || 20;
const d   = msg.as3935;
// dist_km null means chip says "overhead" / <1 km — always disconnect
const km  = (d.distance_km === null) ? 0 : d.distance_km;

msg.strike = {
    source:      'AS3935 (local)',
    distance_km: km,
    energy:      d.energy,
    time:        d.timestamp || new Date().toLocaleString(),
    // AS3935 has no lat/lon — use home location for map pin
    lat:         flow.get('home_lat'),
    lon:         flow.get('home_lon')
};
msg._as3935_km = km;
msg._thr       = thr;

node.status({fill: km <= thr ? 'red' : 'yellow', shape:'dot',
    text: km+' km (thr '+thr+' km)'});
return msg;

const d   = msg.as3935 || {};
const km  = msg._as3935_km;
const ts  = d.timestamp || new Date().toLocaleString();
const line = '<div class="ev-row ev-warn">&#9651; '
           + ts + ' | AS3935 ⚡ ' + km + ' km  energy=' + (d.energy||'—')
           + ' — BELOW threshold, no disconnect</div>';
let log = flow.get('event_log') || [];
log.unshift(line);
if (log.length > 50) log = log.slice(0, 50);
flow.set('event_log', log);
msg.payload = { type: 'log', html: log.join('') };
return msg;

const d   = msg.as3935 || {};
const km  = msg._as3935_km;
const ts  = d.timestamp || new Date().toLocaleString();
const line = '<div class="ev-row ev-err">&#9632; '
           + ts + ' | AS3935 ⚡ ' + km + ' km  energy=' + (d.energy||'—')
           + ' — DISCONNECT triggered</div>';
let log = flow.get('event_log') || [];
log.unshift(line);
if (log.length > 50) log = log.slice(0, 50);
