// Tasmota publishes ON or OFF to stat/<device>/<channel>
const topic   = msg.topic || '';
const payload = (msg.payload || '').toString().toUpperCase().trim();
const on      = (payload === 'ON');

if (topic.indexOf('powerstrip1') !== -1) {
