}
return msg;

const strip = flow.get('power_strip') || 'powerstrip1';
const ch    = flow.get('power_ch')    || 'POWER5';
const rstrip= flow.get('radio_strip') || '4relayboard';
const rch   = flow.get('radio_ch')    || 'POWER1';

// Empty payload = query current state
