// Open-Meteo CAPE-based parser (replaces lightning_potential — null in India).
// CAPE in J/kg from ECMWF/ICON-Global. weather_code is WMO; 95/96/99 = thunderstorm.
//
// Output 1: strike-like payload {lat,lon,km,...} — only when storm-relevant
//           Wires to: Parse Strike (existing)
// Output 2: dashboard log payload — ALWAYS emitted, so dashboard never says "Waiting for data"
//           Wires to: Master Dashboard (557083037f168b22)  ← NEW WIRE TO ADD

const d = msg.payload;
if (!d || !d.hourly || !Array.isArray(d.hourly.cape)) {
    node.error('Open-Meteo: bad response: ' + JSON.stringify(d).substring(0, 200));
    node.status({ fill: 'red', shape: 'dot', text: 'Bad response' });
    return null;
}

const times = d.hourly.time;
const capes = d.hourly.cape;
const wcs = d.hourly.weather_code || [];
const pps = d.hourly.precipitation_probability || [];
const cur_wc = (d.current && d.current.weather_code) || null;

const now = new Date();
const nowHour = now.getFullYear() + '-'
    + String(now.getMonth() + 1).padStart(2, '0') + '-'
    + String(now.getDate()).padStart(2, '0') + 'T'
    + String(now.getHours()).padStart(2, '0') + ':00';

let idx = times.indexOf(nowHour);
if (idx === -1) {
    for (let i = times.length - 1; i >= 0; i--) {
        if (times[i] <= nowHour) { idx = i; break; }
    }
}
if (idx === -1) {
    node.status({ fill: 'grey', shape: 'ring', text: 'No slot found' });
    return null;
}

const cape = capes[idx];
const wc = wcs[idx];
const pp = pps[idx];

// Decide synthetic distance (km). null = calm, no strike emitted.
let km = null;
let why;
const ts_now = (cur_wc !== null && [95, 96, 99].includes(cur_wc));
const ts_hr = [95, 96, 99].includes(wc);
const shower = [80, 81, 82].includes(wc);

if (ts_now) { km = 0; why = 'TS NOW (wc=' + cur_wc + ')'; }
else if (ts_hr) { km = 0; why = 'TS hour (wc=' + wc + ')'; }
else if (shower && cape >= 1000) { km = 20; why = 'Shower+CAPE ' + cape; }
else if (cape >= 2500) { km = 10; why = 'Severe CAPE ' + cape; }
else if (cape >= 1500) { km = 40; why = 'Strong CAPE ' + cape; }
else if (cape >= 800) { km = 100; why = 'Moderate CAPE ' + cape; }
else { why = 'Calm CAPE ' + cape; }

// ── Derive OM storm-probability state (cold / lit / severe) ──
// Trigger Disconnect reads flow.om_state to corroborate medium-zone
// AS3935 lightning. OM never directly fires disconnect — it's a
// probability indicator, not a strike detector.
const cape_lit_thr    = flow.get('cfg_om_cape_thresh')        || 800;
const cape_severe_thr = flow.get('cfg_om_cape_severe_thresh') || 2500;
const om_window_min   = flow.get('cfg_om_lit_window_min')     || 20;
const tsActive = ts_now || ts_hr;
let om_state = 'cold';
if      (tsActive && cape >= cape_severe_thr) om_state = 'severe';
else if (tsActive && cape >= cape_lit_thr)    om_state = 'lit';
flow.set('om_state', om_state);
flow.set('om_state_until', Math.floor(Date.now() / 1000) + om_window_min * 60);
flow.set('om_cape_latest', cape);
flow.set('om_wc_latest',   cur_wc);

const lat = flow.get('home_lat');
const lon = flow.get('home_lon');

// Always emit dashboard log (output 2)
const logMsg = {
    payload: {
        type: 'log',
        html: 'Open-Meteo: ' + why
            + (km !== null ? ' → ' + km + ' km' : ' (no action)')
            + ' @ ' + times[idx]
    }
};

// Set node status
node.status({
    fill: km === null ? 'green' : km <= 30 ? 'red' : km <= 80 ? 'yellow' : 'blue',
    shape: 'dot',
    text: why + (km !== null ? ' → ' + km + 'km' : '')
});

if (km === null) {
    return [null, logMsg];   // calm — only update dashboard
}

// Storm-relevant — emit strike payload to existing Parse Strike chain
const strikeMsg = {
    payload: {
        lat: lat,
        lon: lon,
        pol: 0,
        region: 0,
        source: 'Open-Meteo',
        om_cape: cape,
        om_wc: wc,
        om_curwc: cur_wc,
        om_time: times[idx]
    }
};
return [strikeMsg, logMsg];

const lat = flow.get('home_lat') || 13.1875;
const lon = flow.get('home_lon') || 77.625;
msg.url = 'https://api.open-meteo.com/v1/forecast'
  + '?latitude='  + lat
  + '&longitude=' + lon
  + '&current=temperature_2m,apparent_temperature,relative_humidity_2m,'
  + 'rain,weather_code,wind_speed_10m,wind_direction_10m,surface_pressure'
  + '&hourly=temperature_2m,weather_code,precipitation_probability'
  + '&wind_speed_unit=kmh&timezone=Asia%2FKolkata&forecast_days=1';
return msg;

const WMO_TEXT={0:'Clear Sky',1:'Mainly Clear',2:'Partly Cloudy',3:'Overcast',45:'Foggy',48:'Icy Fog',51:'Light Drizzle',53:'Drizzle',55:'Dense Drizzle',61:'Slight Rain',63:'Moderate Rain',65:'Heavy Rain',71:'Slight Snow',73:'Moderate Snow',75:'Heavy Snow',77:'Snow Grains',80:'Slight Showers',81:'Moderate Showers',82:'Violent Showers',95:'Thunderstorm',96:'Thunderstorm+Hail',99:'Thunderstorm+Hail'};
const WMO_EMOJI={0:'☀️',1:'🌤️',2:'⛅',3:'☁️',45:'🌫️',48:'🌫️',51:'🌦️',53:'🌦️',55:'🌧️',61:'🌧️',63:'🌧️',65:'🌧️',71:'❄️',73:'❄️',75:'❄️',77:'❄️',80:'🌦️',81:'🌦️',82:'⛈️',95:'⛈️',96:'⛈️',99:'⛈️'};
function windDir(d){return['N','NE','E','SE','S','SW','W','NW'][Math.round(d/45)%8];}
const d=msg.payload;
if(!d||!d.current){node.error('Bad response');return null;}
const c=d.current,hr=d.hourly;
const now=new Date();
const nowISO=now.getFullYear()+'-'+String(now.getMonth()+1).padStart(2,'0')+'-'+String(now.getDate()).padStart(2,'0')+'T'+String(now.getHours()).padStart(2,'0')+':00';
let si=hr.time.indexOf(nowISO);
if(si===-1){for(let i=hr.time.length-1;i>=0;i--){if(hr.time[i]<=nowISO){si=i;break;}}}
if(si===-1)si=0;
const hourly=[];
for(let i=si;i<Math.min(si+13,hr.time.length);i++){
  const t=new Date(hr.time[i]);
  hourly.push({h:String(t.getHours()).padStart(2,'0')+':00',temp:Math.round(hr.temperature_2m[i]),emoji:WMO_EMOJI[hr.weather_code[i]]||'🌡️',pop:hr.precipitation_probability[i]||0});
}
const wxData={
  temp:Math.round(c.temperature_2m),
  feels:Math.round(c.apparent_temperature),
  hum:c.relative_humidity_2m,
  rain:(c.rain||0).toFixed(1),
  wind:Math.round(c.wind_speed_10m),
  windDir:windDir(c.wind_direction_10m||0),
  pressure:Math.round(c.surface_pressure),
  cond:WMO_TEXT[c.weather_code]||'Unknown',
  emoji:WMO_EMOJI[c.weather_code]||'🌡️',
  hourly:hourly,
  updated:now.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'})
};
flow.set('wxData', wxData);
node.status({fill:'green',shape:'dot',text:wxData.temp+'°C '+wxData.cond});
// Output 1 → Header ui_template (plain payload)
// Output 2 → Master Dashboard (typed payload)
const msg2 = {payload: {type:'weather', wx: wxData}};
msg.payload = wxData;
return [msg, msg2];

// Replay bypass state on every Refresh Stats tick (30 s) so the bypass banner +
// vertical switch survive page reload. Master Dashboard receives bypass_state and
// repaints the button + banner + countdown.
const active = flow.get('bypass_active') === true;
const expiresAt = flow.get('bypass_expires_at');

if (!active) {
    msg.payload = { type: 'bypass_state', active: false, expiresAt: 0 };
    return msg;
}

// Active — but check expiry server-side as a safety net (clock skew, restart edge cases)
if (typeof expiresAt === 'number' && Date.now() >= expiresAt) {
    flow.set('bypass_active', false);
    flow.set('bypass_expires_at', null);
    msg.payload = { type: 'bypass_state', active: false, expiresAt: 0 };
    return msg;
}

msg.payload = { type: 'bypass_state', active: true, expiresAt: expiresAt };
return msg;

flow.set('last_strike_km', null);
flow.set('strikes', []);     // legacy key — clear in case anything still reads it
flow.set('event_log', []);
return { payload: { type: 'clear' } };

// Receives msg from MQTT in (status or hb). Caches in flow context for
// refresh-replay, then forwards typed payload to Master Dashboard.
let raw;
try { raw = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; }
catch (e) { return null; }
if (!raw || typeof raw !== 'object') return null;

if (msg.topic.endsWith('/status')) {
    flow.set('as3935_status', raw);
    msg.payload = Object.assign({ type: 'as3935_ready' }, raw);
    node.status({fill: raw.event === 'ready' ? 'green' : 'red',
                 shape: 'dot', text: 'status: ' + raw.event});
} else if (msg.topic.endsWith('/hb')) {
    flow.set('as3935_hb', raw);
    const c = raw.counters || {};
    msg.payload = Object.assign({ type: 'as3935_hb' }, raw);
    node.status({fill:'green', shape:'dot',
                 text: 'hb up=' + raw.uptime_s + ' irq=' + (c.irq||0)});
} else {
    return null;
}
return msg;

// Triggered by Refresh Stats (every 30s). Re-emits cached status + hb so
// the dashboard panel survives page refresh.
const out = [];
const status = flow.get('as3935_status');
const hb     = flow.get('as3935_hb');
if (status) out.push({ payload: Object.assign({ type: 'as3935_ready' }, status) });
if (hb)     out.push({ payload: Object.assign({ type: 'as3935_hb'    }, hb)     });
if (out.length === 0) return null;
return [out];

// Handles POST /lightning/bypass {action: 'on'|'off'}
// Outputs:
//   1 → Master Dashboard (bypass_state + log entries)
//   2 → Reconnect Timer (cancel any active timer when bypass ON)
//   3 → Execute Reconnect (force ant + radio ON when bypass ON)
//
// Auto-off after 120 minutes via setTimeout (lost on Node-RED restart, fine —
// Init Defaults clears bypass on every deploy/restart anyway).

const BYPASS_DURATION_MS = 120 * 60 * 1000;

// Manual call from the dashboard
let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (e) { payload = {}; }
}
const action = (payload && payload.action) || null;
node.warn('Bypass Handler: action=' + action + ' typeof payload=' + typeof msg.payload);

// Helper — cancel pending auto-off
function cancelAutoOff(){
    const t = context.get('autoOffTimer');
    if (t) { clearTimeout(t); context.set('autoOffTimer', null); }
}

if (action === 'on') {
    const expiresAt = Date.now() + BYPASS_DURATION_MS;
    flow.set('bypass_active', true);
    flow.set('bypass_expires_at', expiresAt);
    cancelAutoOff();
    const t = setTimeout(function(){
        flow.set('bypass_active', false);
        flow.set('bypass_expires_at', null);
        context.set('autoOffTimer', null);
        node.status({fill:'grey', shape:'ring', text:'auto-off (2h expired)'});
        node.send([[
            { payload: { type: 'bypass_state', active: false, expiresAt: 0 } },
            { payload: { type: 'log', html: 'BYPASS expired (2h timeout) — normal mode resumed' } }
        ], null, null]);
    }, BYPASS_DURATION_MS);
    context.set('autoOffTimer', t);

    node.status({fill:'yellow', shape:'dot', text:'BYPASS ON · 120 min'});

    // Output 1: dashboard state + log
    const stateMsg = { payload: { type: 'bypass_state', active: true, expiresAt: expiresAt } };
    const logMsg   = { payload: { type: 'log', html: 'BYPASS activated — strikes alert only · expires in 120 min' } };
    // Output 2: cancel reconnect timer (kills any pending countdown)
    const cancelMsg = { payload: 'cancel' };
    // Output 3: force reconnect (turns ant + radio ON immediately)
    const reconnectMsg = { payload: 'reconnect', cmd: 'BYPASS_ON', reason: 'bypass activated' };

    return [[stateMsg, logMsg], cancelMsg, reconnectMsg];
}

if (action === 'off') {
    flow.set('bypass_active', false);
    flow.set('bypass_expires_at', null);
    cancelAutoOff();
    node.status({fill:'grey', shape:'ring', text:'BYPASS OFF (manual)'});

    const stateMsg = { payload: { type: 'bypass_state', active: false, expiresAt: 0 } };
    const logMsg   = { payload: { type: 'log', html: 'BYPASS deactivated (manual) — normal mode' } };
    return [[stateMsg, logMsg], null, null];
}

node.warn('Bypass: unknown action: ' + action);
return null;

for (var i=1; i<=5; i++) {
