var topic=msg.topic,payload=msg.payload;
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){}}
var msgs=[];
if(typeof payload==='object'&&payload!==null){
for(var i=1;i<=5;i++){var key='POWER'+i;if(payload[key]!==undefined){msgs.push({topic:'powerstrip3/plug'+i+'/state',payload:payload[key]==='ON'});}}
}else if(typeof payload==='string'){var match=topic.match(/POWER(\d+)$/);if(match){msgs.push({topic:'powerstrip3/plug'+match[1]+'/state',payload:payload==='ON'});}}
return[msgs];

for (var i=1; i<=4; i++) {
    node.send({topic: 'cmnd/4relayboard/POWER'+i, payload: ''});
}
return null;

var topic=msg.topic,payload=msg.payload;
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){}}
var msgs=[];
if(typeof payload==='object'&&payload!==null){
for(var i=1;i<=4;i++){var key='POWER'+i;if(payload[key]!==undefined){msgs.push({topic:'4relayboard/plug'+i+'/state',payload:payload[key]==='ON'});}}
}else if(typeof payload==='string'){var match=topic.match(/POWER(\d+)$/);if(match){msgs.push({topic:'4relayboard/plug'+match[1]+'/state',payload:payload==='ON'});}}
return[msgs];

var topic=msg.topic,payload=msg.payload;
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){}}
var out=[];
function extractEnergy(e){
if(!e||typeof e!=='object')return;
if(e.Voltage!==undefined)out.push({topic:'energy/voltage',payload:e.Voltage});
if(e.Current!==undefined)out.push({topic:'energy/current',payload:e.Current});
var pwr=e.Power!==undefined?e.Power:e.ActivePower;
if(pwr!==undefined)out.push({topic:'energy/power',payload:pwr});
if(e.Today!==undefined)out.push({topic:'energy/today',payload:e.Today});
if(e.Total!==undefined)out.push({topic:'energy/total',payload:e.Total});}
var CHIP_KEYS=['ENERGY','BL0937','CSE7766','HLW8012','PZEM004T','ADE7953'];
if(typeof payload==='object'&&payload!==null){
var pwr=(payload.POWER!==undefined)?payload.POWER:(payload.POWER1!==undefined)?payload.POWER1:null;
if(pwr!==null)out.push({topic:'switch/state',payload:pwr==='ON'?1:0});
if(payload.StatusSNS){var sns=payload.StatusSNS;for(var k=0;k<CHIP_KEYS.length;k++){if(sns[CHIP_KEYS[k]]){extractEnergy(sns[CHIP_KEYS[k]]);break;}}if(!out.length)extractEnergy(sns);}
var foundChip=false;
for(var j=0;j<CHIP_KEYS.length;j++){if(payload[CHIP_KEYS[j]]){extractEnergy(payload[CHIP_KEYS[j]]);foundChip=true;break;}}
if(!foundChip)extractEnergy(payload);
}else if(typeof payload==='string'){if(/POWER\d*$/.test(topic))out.push({topic:'switch/state',payload:payload==='ON'?1:0});}
return[out];

var states = flow.get('power_states') || {};

// Timer-only trigger from Rotator Auto-Off Timer (no topic)
if (msg.rotatorTimerEnd !== undefined && !msg.topic) {
    msg.payload = states;
    return msg;
}

var topic = msg.topic;
if (!topic || topic.indexOf('stat/') !== 0) return null;
if (topic.indexOf('/STATUS') !== -1) return null;

// Parse stat/<device>/RESULT JSON and extract any POWER<n> keys
if (topic.indexOf('/RESULT') !== -1) {
    var device = topic.split('/')[1];
    var pl = msg.payload;
    if (typeof pl === 'string') { try { pl = JSON.parse(pl); } catch(e) { return null; } }
    if (typeof pl !== 'object' || pl === null) return null;
    var updated = false;
    Object.keys(pl).forEach(function(k){
        var m = k.match(/^POWER(\d*)$/);
        if (m) {
            var n = m[1] || '1';
            states['stat/'+device+'/POWER'+n] = String(pl[k]).toUpperCase();
            updated = true;
        }
    });
    if (!updated) return null;
    flow.set('power_states', states);
    msg.payload = states;
    msg.rotatorTimerEnd = flow.get('rotatorTimerEnd') || null;
    return msg;
}

// Normal stat/<device>/POWER<n> update
var val = msg.payload.toString().toUpperCase().trim();
states[topic] = val;
flow.set('power_states', states);
msg.payload = states;
msg.rotatorTimerEnd = flow.get('rotatorTimerEnd') || null;
return msg;

var topic=msg.topic;
var states=flow.get('power_states')||{};
var cur=states[topic];
var newState=(cur==='ON')?'OFF':'ON';
states[topic]=newState;
flow.set('power_states',states);
msg.payload=newState;
return msg;

var ctx=flow.get('energy_state')||{};
var t=msg.topic,p=msg.payload;
if(t==='energy/voltage')ctx.voltage=p;
else if(t==='energy/current')ctx.current=p;
else if(t==='energy/power')ctx.power=p;
else if(t==='energy/today')ctx.today=p;
else if(t==='energy/total')ctx.total=p;
else return null;
flow.set('energy_state',ctx);
msg.payload=ctx;
return msg;

var state = msg.payload.toString().toUpperCase().trim();
var now = Date.now();
var timer = context.get('timer');
var lastOff = context.get('lastOff') || 0;

if (state === 'ON') {
    // Ignore ON echoes while a timer is already running
    if (timer) return null;
    // Ignore ON echoes within 10s after we sent an OFF (breaks reset loop
    // caused by spurious stat/POWER2 republishes)
    if (now - lastOff < 10000) return null;
    // Fresh ON → start the 60s auto-off timer
    var duration = 5 * 60 * 1000;
    var endTime = now + duration;
    flow.set('rotatorTimerEnd', endTime);
    var t = setTimeout(function() {
        context.set('timer', null);
        context.set('lastOff', Date.now());
        flow.set('rotatorTimerEnd', null);
        node.send([
            { rotatorTimerEnd: null },
            { payload: 'OFF', topic: 'cmnd/powerstrip1/POWER2' }
        ]);
    }, duration);
    context.set('timer', t);
    node.status({fill:'yellow', shape:'dot', text:'Timer running — 5 mins'});
    return [{ rotatorTimerEnd: endTime }, null];
} else {
    if (timer) { clearTimeout(timer); context.set('timer', null); }
    context.set('lastOff', now);
    flow.set('rotatorTimerEnd', null);
    node.status({fill:'grey', shape:'ring', text:'OFF — timer cleared'});
    return [{ rotatorTimerEnd: null }, null];
}

// Try file store first (fastest, survives reboot)
var ft = flow.get('workedTable', 'file');
if (ft && Object.keys(ft).length > 100) {
    flow.set('workedTable', ft);
    flow.set('entityWorked', flow.get('entityWorked', 'file') || {});
    flow.set('dxccModeWorked', flow.get('dxccModeWorked', 'file') || {});
    flow.set('workedStats', flow.get('workedStats', 'file') || {});
    flow.set('dxccReady', true);                                          // ← NEW
    node.status({ fill: 'blue', shape: 'dot', text: 'Restored ' + Object.keys(ft).length + ' entities from file store' });
    return msg;
}

var existing = flow.get('workedTable');
if (existing && Object.keys(existing).length > 100) {
    flow.set('dxccReady', true);                                          // ← NEW
    node.status({ fill: 'grey', shape: 'dot', text: 'Already loaded - skipping' });
    return null;
}

var flowsDir = flow.get('cfg_flows_dir') || os.homedir() + '/.node-red';
var locations = [
    flowsDir + '/nr_dxcc_seed.json',
    os.homedir() + '/.node-red/nr_dxcc_seed.json'
];
var seed = null; var usedPath = null; var errors = [];
for (var i = 0; i < locations.length; i++) {
    try {
        if (fs.existsSync(locations[i])) {
            var data = fs.readFileSync(locations[i], 'utf8');
            seed = JSON.parse(data);
            usedPath = locations[i];
            break;
        } else { errors.push(locations[i] + ' not found'); }
    } catch (e) { errors.push(locations[i] + ': ' + e.message); }
}
if (!seed) {
    node.error('nr_dxcc_seed.json not found. Tried: ' + errors.join(' | '));
    node.status({ fill: 'red', shape: 'dot', text: 'File not found - see debug' });
    return null;
}
flow.set('workedTable', seed.workedTable);
flow.set('entityWorked', seed.entityWorked);
flow.set('workedStats', seed.stats);
flow.set('dxccReady', true);                                              // ← NEW
node.status({ fill: 'green', shape: 'dot', text: seed.stats.entities + ' entities, ' + seed.stats.bandSlots + ' slots from ' + usedPath });
msg.payload = seed.stats;
return msg;

var s = msg.payload;
msg.payload = {entities:s.entities,bandSlots:s.bandSlots,confirmed:s.confirmed,unconfirmed:s.unconfirmed,updated:new Date().toLocaleTimeString()};
msg.topic = 'dxcc_stats';
return msg;

if (!flow.get('dxccReady')) {
    node.status({ fill: 'grey', shape: 'dot', text: 'Paused — reference data loading...' });
    return null;
}

var prefixMap = flow.get('dxccPrefixMap') || {};
var exceptions = flow.get('dxccExceptions') || {};
var seedNames = flow.get('dxccSeedNames') || {};

if (Object.keys(prefixMap).length === 0) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'Waiting for cty.xml...' });
    return null;
}

function resolveDXCC(call) {
    call = call.toUpperCase();
    if (exceptions[call]) return exceptions[call];
    var parts = call.split('/');
    var bestDxcc = null, bestLen = 0;
    parts.forEach(function (part) {
        if (part.length <= 2) return;
        for (var len = Math.min(5, part.length); len >= 1; len--) {
            var pfx = part.substring(0, len);
            if (prefixMap[pfx]) {
                if (len > bestLen) { bestLen = len; bestDxcc = prefixMap[pfx]; }
                break;
            }
        }
    });
    return bestDxcc || parts[0].substring(0, 4);
}

var spot = msg.spot;
if (!spot) return null;

var blacklist = flow.get('dxccBlacklist') || [];
if (blacklist.indexOf(spot.call) !== -1) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' blacklisted' });
    return null;
}

var band = (spot.band || '').toString().toUpperCase().trim();
if (!band) return null;

var entityWorked = flow.get('entityWorked') || {};
if (Object.keys(entityWorked).length === 0) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'Waiting for Club Log data...' });
    return null;
}

var seedKey = resolveDXCC(spot.call);
spot.dxcc = seedKey;
spot.entity = seedNames[seedKey] || seedKey;

if (!seedNames[seedKey]) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' unknown DXCC: ' + seedKey });
    return null;
}

var ew = entityWorked[seedKey];
var bw = ew ? ew[band] : null;

var entityExists = !!ew && Object.keys(ew).length > 0;
var bandWorked = !!(bw && (bw.confirmed || bw.unconfirmed));
var bandConfirmed = !!(bw && bw.confirmed);

function getModeCat(m) {
    if (!m) return null;
    var u = m.toUpperCase();
    if (u === 'CW') return 'cw';
    if (u === 'FT8' || u === 'FT4' || u === 'RTTY' || u === 'PSK31' || u === 'DATA' || u === 'JS8') return 'data';
    if (u === 'USB' || u === 'LSB' || u === 'SSB' || u === 'AM' || u === 'FM' || u === 'PHONE') return 'phone';
    return null;
}
var modeCat = getModeCat(spot.mode);
var modeWorkedMap = flow.get('dxccModeWorked') || {};
var modeEntry = modeWorkedMap[seedKey];
var modeAlreadyWorked = !!(modeEntry && modeCat && modeEntry[modeCat]);

// Mode filter — applies to all alerts for this spot
var modeCatForFilter = getModeCat(spot.mode);
if (modeCatForFilter === 'cw' && flow.get('filterModeCW', 'file') === false) return null;
if (modeCatForFilter === 'phone' && flow.get('filterModePhone', 'file') === false) return null;
if (modeCatForFilter === 'data' && flow.get('filterModeData', 'file') === false) return null;

// Band filter — applies to all alerts for this spot
var filterBands = flow.get('filterBands', 'file');
if (filterBands && Object.keys(filterBands).length > 0 && !filterBands[band]) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' filtered (' + band + ')' });
    return null;
}

var filterNewDxcc = flow.get('filterNewDxcc', 'file');
var filterNewBand = flow.get('filterNewBand', 'file');
var filterNewBandUnconf = flow.get('filterNewBandUnconf', 'file');
var filterNewMode = flow.get('filterNewMode', 'file');
var filterNewModeUnconf = flow.get('filterNewModeUnconf', 'file');

var confStatus = '\u2014';
if (bw) confStatus = bw.confirmed ? 'confirmed \u2713' : 'unconfirmed \u2717';

// Build independent alerts
var alerts = [];

if (!entityExists) {
    // NEW DXCC — exclusive, no band/mode alerts on top
    if (filterNewDxcc !== false) {
        alerts.push({ type: 'NEW_DXCC', color: '#f85149', label: 'NEW DXCC', unconf: false });
    }
} else {
    // NEW BAND (confirmed) or NEW BAND unconfirmed
    if (!bandWorked) {
        if (filterNewBand !== false)
            alerts.push({ type: 'NEW_BAND', color: '#58a6ff', label: 'NEW BAND', unconf: false });
    } else if (bandWorked && !bandConfirmed) {
        if (filterNewBandUnconf !== false)
            alerts.push({ type: 'NEW_BAND_UNCONF', color: '#2d6aad', label: '? BAND', unconf: true });
    }
    // NEW MODE (confirmed) or NEW MODE unconfirmed
    if (modeCat && !modeAlreadyWorked) {
        if (filterNewMode !== false)
            alerts.push({ type: 'NEW_MODE', color: '#e3b341', label: 'NEW MODE', unconf: false });
    } else if (modeCat && modeAlreadyWorked) {
        // mode worked but check if this specific band+mode slot is unconfirmed
        var bwMode = bw;
        if (bwMode && !bwMode.confirmed) {
            if (filterNewModeUnconf !== false)
                alerts.push({ type: 'NEW_MODE_UNCONF', color: '#9a7030', label: '? MODE', unconf: true });
        }
    }
}

if (alerts.length === 0) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' worked (' + spot.entity + ' ' + band + ')' });
    return null;
}

// Node status — show all alert types
var statusFill = alerts[0].color === '#58a6ff' ? 'blue' :
    alerts[0].color === '#e3b341' ? 'yellow' : 'red';
node.status({
    fill: statusFill, shape: 'dot',
    text: alerts.map(function (a) { return a.label; }).join('+') + ': ' + spot.call + ' ' + spot.entity + ' ' + band
});

// Fire one msg per alert
alerts.forEach(function (a) {
    var alertObj = {
        type: a.type, color: a.color, label: a.label, unconf: a.unconf,
        call: spot.call, entity: spot.entity, dxcc: seedKey,
        band: band, mode: spot.mode, freqKHz: spot.freqKHz, freqMHz: spot.freqMHz,
        spotter: spot.spotter, comment: spot.comment, confStatus: confStatus,
        time: new Date().toLocaleTimeString()
    };
    node.send({ spot: spot, alert: alertObj, payload: alertObj });
});
return null;

var a = msg.alert;
var row = {
    time: a.time,
    type: a.type,
    label: a.label,
    call: a.call,
    entity: a.entity,
    band: a.band,
    mode: a.mode,
    freq: a.freqMHz + ' MHz',
    spotter: a.spotter,
    conf: a.confStatus,
    color: a.color,
    ts: Date.now(),
    alertType: a.type
};

var ttlMs = (flow.get('spotTTL', 'file') || 20) * 60 * 1000;
var alerts = flow.get('alertList') || [];
var now = Date.now();

// TTL expiry + dedup on call+band+mode+alertType — drops any existing row
// matching the new alert before pushing, so identical alerts re-firing after
// the upstream 60 s spot-dedup window don't double-render in the table.
alerts = alerts.filter(function (r) {
    if ((now - (r.ts || 0)) >= ttlMs) return false;
    if (r.call === row.call &&
        r.band === row.band &&
        r.mode === row.mode &&
        r.alertType === row.alertType) return false;
    return true;
});
alerts.unshift(row);


if (alerts.length > 200) alerts = alerts.slice(0, 200);
flow.set('alertList', alerts);

var filterBands = flow.get('filterBands', 'file');
var filterNewDxcc = flow.get('filterNewDxcc', 'file');
var filterNewBand = flow.get('filterNewBand', 'file');
var filterNewBandUnconf = flow.get('filterNewBandUnconf', 'file');
var filterNewMode = flow.get('filterNewMode', 'file');
var filterNewModeUnconf = flow.get('filterNewModeUnconf', 'file');

var visible = alerts.filter(function (r) {
    if (filterBands && Object.keys(filterBands).length > 0 && !filterBands[r.band]) return false;
    if (r.alertType === 'NEW_DXCC' && filterNewDxcc === false) return false;
    if (r.alertType === 'NEW_BAND' && filterNewBand === false) return false;
    if (r.alertType === 'NEW_BAND_UNCONF' && filterNewBandUnconf === false) return false;
    if (r.alertType === 'NEW_MODE' && filterNewMode === false) return false;
    if (r.alertType === 'NEW_MODE_UNCONF' && filterNewModeUnconf === false) return false;
    return true;
});

msg.payload = visible;
msg.topic = 'dx_alert';
return msg;

var a = msg.alert;
var base = flow.get('cfg_alertTopic','file') || 'shack/dxcc/alert';
msg.topic   = base + '/' + a.type;
msg.payload = JSON.stringify({type:a.type,call:a.call,entity:a.entity,dxcc:a.dxcc,band:a.band,mode:a.mode,freqKHz:a.freqKHz,freqMHz:a.freqMHz,color:a.color,confStatus:a.confStatus,spotter:a.spotter,time:a.time});
return msg;

var a = msg.alert;
if (!a) return null;

// Colour by alert type: NEW_DXCC=red, NEW_MODE=amber, NEW_BAND=blue
var colorMap = {
    'NEW_DXCC': '0xFFFF3333',   // red
    'NEW_MODE': '0xFFFFAA00',   // amber
    'NEW_BAND': '0xFF3399FF'    // blue
};
var color = colorMap[a.type] || '0xFF00FCCC';

var seq = (flow.get('spotSeq') || 7000) + 1;
flow.set('spotSeq', seq);
var ts = Math.floor(Date.now() / 1000);
var ttl = (flow.get('spotTTL', 'file') || 20) * 60;

var cmd = 'C' + seq + '|spot add' +
    ' rx_freq='          + a.freqMHz +
    ' callsign='         + a.call +
    ' mode='             + a.mode +
    ' comment='          + (a.label + '-' + a.entity).replace(/\s+/g,'_').substring(0,20) +
    ' spotter_callsign=' + (a.spotter || flow.get('cfg_cl_callsign') || '') +
    ' timestamp='        + ts +
    ' color='            + color +
    ' priority=2' +
    ' lifetime_seconds=' + ttl +
