msg.payload = cmd;
node.status({fill: a.color==='red'?'red':a.color==='amber'?'yellow':'blue',
    shape:'dot', text: a.type + ': ' + a.call + ' → Flex'});
return msg;

var a = msg.alert;
var icons = {NEW_DXCC:'🔴',NEW_BAND:'🔵',NEW_MODE:'🟡'};
msg.payload = (icons[a.type]||'📻')+' '+a.label+': '+a.call+' ('+a.entity+') '+a.band+' '+a.mode+' @ '+a.freqMHz+' MHz';
msg.topic = a.type;
return msg;

if(msg.topic !== 'clear_alerts' && msg.topic !== 'clear') return null;
flow.set('alertList',[]);
msg.payload=[];
msg.topic='dx_alert';
return msg;

// Blacklist Manager
// msg.topic = 'blacklist_add'    → msg.payload = callsign to add
// msg.topic = 'blacklist_remove' → msg.payload = callsign to remove
// msg.topic = 'blacklist_load'   → load from file
// msg.topic = 'blacklist_get'    → return current list

var flowsDir = flow.get('cfg_flows_dir') || os.homedir() + '/.node-red';
var path  = flowsDir + '/nr_dxcc_blacklist.json';


function loadList() {
    try {
        if (fs.existsSync(path)) {
            return JSON.parse(fs.readFileSync(path, 'utf8'));
        }
    } catch(e) { node.warn('Blacklist load error: ' + e.message); }
    return [];
}

function saveList(list) {
    try {
        fs.writeFileSync(path, JSON.stringify(list, null, 2));

        return true;
    } catch(e) { node.warn('Blacklist save error: ' + e.message); return false; }
}

var list = loadList();
var call = (msg.payload || '').toString().toUpperCase().trim();

if (msg.topic === 'blacklist_add' && call) {
    if (list.indexOf(call) === -1) {
        list.push(call);
        list.sort();
        saveList(list);
        node.status({fill:'red', shape:'dot', text:'Blacklisted: ' + call});
        flow.set('dxccBlacklist', list);
        node.warn('Blacklisted: ' + call);
    }
} else if (msg.topic === 'blacklist_remove' && call) {
    list = list.filter(function(c) { return c !== call; });
    saveList(list);
    flow.set('dxccBlacklist', list);
    node.status({fill:'green', shape:'dot', text:'Removed: ' + call});
} else if (msg.topic === 'blacklist_load') {
    flow.set('dxccBlacklist', list);
    node.status({fill:'blue', shape:'dot', text: list.length + ' blacklisted'});
}

msg.payload  = list;
msg.topic    = 'blacklist_update';
msg.topic = 'blacklist';
msg.topic='blacklist';
return msg;

initialize:
var path = os.homedir() + '/.node-red/projects/vu2cpl-shack/nr_dxcc_blacklist.json';
try {
    if (fs.existsSync(path)) {
        var list = JSON.parse(fs.readFileSync(path, 'utf8'));
        flow.set('dxccBlacklist', list);
        node.log('Blacklist loaded: ' + list.length + ' entries');
    } else {
        flow.set('dxccBlacklist', []);
    }
} catch(e) { flow.set('dxccBlacklist', []); }

func:
// Only pass blacklist_add and blacklist_remove topics
// Drop everything else (especially the forwarded payload arrays)
if (msg.topic === 'blacklist_add' || msg.topic === 'blacklist_remove') {
    return msg;
}
return null;

// ═══════════════════════════════════════════════════
// DXCC TRACKER — CREDENTIALS
//
// Secrets (apikey, password, telegram token) load from systemd
// environment variables, set in:
//   /etc/systemd/system/nodered.service.d/secrets.conf  (chmod 600)
//
// Non-sensitive config stays inline below.
// To rotate a secret: edit the secrets.conf file + `systemctl
// restart nodered` — flows.json never touches the new value.
// ═══════════════════════════════════════════════════

var cfg = {
    // ── Secrets — from systemd Environment= ────────────────────
    cl_apikey: env.get('CLUBLOG_API_KEY') || '',
    cl_password: env.get('CLUBLOG_PASSWORD') || '',
    tg_token: env.get('TELEGRAM_TOKEN') || '',

    // ── Non-sensitive config — inline ─────────────────────────
    cl_email: 'vu2cpl@gmail.com',
    cl_callsign: 'VU2CPL',
    cl_login_ssid: '-1',                  // appended to callsign for cluster login (avoids dup-detection)
    tg_chat_id: '784711092'
};

Object.keys(cfg).forEach(function (k) {
    flow.set('cfg_' + k, cfg[k]);
    try { flow.set('cfg_' + k, cfg[k], 'file'); } catch (e) { }
});

flow.set('cfg_flows_dir', os.homedir() + '/.node-red/projects/vu2cpl-shack');

// Validate every required env-var is set
var missing = [];
if (!cfg.cl_apikey) missing.push('CLUBLOG_API_KEY');
if (!cfg.cl_password) missing.push('CLUBLOG_PASSWORD');
if (!cfg.tg_token) missing.push('TELEGRAM_TOKEN');

if (missing.length) {
    node.error('Missing systemd env vars: ' + missing.join(', ') +
        ' — see /etc/systemd/system/nodered.service.d/secrets.conf');
    node.status({ fill: 'red', shape: 'dot', text: 'Missing: ' + missing.join(',') });
} else {
    node.status({
        fill: 'green', shape: 'dot',
        text: 'Config loaded: ' + cfg.cl_callsign + cfg.cl_login_ssid +
            ' / tg:' + cfg.tg_chat_id
    });
}
return null;

try {
    var r = JSON.parse(msg.payload);
    if (r.ok) {
        node.status({fill:'green', shape:'dot', text:'Sent OK'});
    } else {
        node.status({fill:'red', shape:'dot', text:'Error: ' + r.description});
