// ─────────────────────────────────────────────────────────────
// Handles ALL clusters feeding into this single node.
// A) Login  — detects 'login:' and replies VU2CPL on same session
// B) Parse  — turns DX spot lines into SmartSDR spot add commands
// C) Status — tracks per-source spot count + last spot time
// D) Dedup  — suppresses duplicate callsign+freq within 60 seconds
// ─────────────────────────────────────────────────────────────

var line = (msg.payload || '').trim();
var src = msg.topic || 'unknown';

// ── Source key map (topic → display name) ─────────────────────
var srcMap = {
    'cluster1': 'N2WQ',
    'cluster2': 'VU2OY',
    'cluster3': 'VU2CPL',
    'cluster4': 'VE7CC'
};

// ── A) LOGIN ─────────────────────────────────────────────────
// ── A) LOGIN ─────────────────────────────────────────────────
// Match a login PROMPT only — a short line ending with the indicator.
// Avoids false-positives like N2WQ's welcome banner "Last login:
// (first login) from ..." which previously triggered a duplicate
// VU2CPL send and got us booted with "Another login with your call".
var lc = line.trim().toLowerCase();
if (lc.length < 40 && (
    lc.endsWith('login:') ||
    lc.endsWith('please login') ||
    lc.endsWith('please login:') ||
    lc.endsWith('callsign:') ||
    lc.endsWith('callsign please:') ||
    lc.endsWith('your callsign:') ||
    lc.endsWith('enter your callsign:')
)) {
    node.status({ fill: 'blue', shape: 'dot', text: src + ' → login sent' });
    return [
        { payload: (flow.get('cfg_cl_callsign') || 'VU2CPL') + (flow.get('cfg_cl_login_ssid') || '') + '\r\n', _session: msg._session },
        null, null
    ];
}


// ── Skip non-DX lines ─────────────────────────────────────────
if (!line.startsWith('DX de')) {
    node.status({ fill: 'grey', shape: 'ring', text: '[' + src + '] ' + line.substring(0, 50) });
    return [null, null, null];
}

// ── B) PARSE ─────────────────────────────────────────────────
var re = /^DX de\s+([A-Z0-9\/\-#]+):\s+([\d.]+)\s+([A-Z0-9\/\-#]+)\s*(.*?)\s*(\d{4}Z?)?\s*$/i;
var m = line.match(re);
if (!m) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'no match: ' + line.substring(0, 45) });
    return [null, null, null];
}

var spotter = m[1].toUpperCase();
var freqKHz = parseFloat(m[2]);
var dxCall = m[3].toUpperCase();
var comment = (m[4] || '').trim();
var freqMHz = (freqKHz / 1000).toFixed(6);

var now = Date.now();

// ── C) CLUSTER STATUS — before dedup so all spots counted ─────
var cs = flow.get('clusterStatus') || {};
if (!cs[src]) cs[src] = { name: srcMap[src] || src, host: src, count: 0, lastSpot: '', lastSpotTs: 0, connected: false, reconnecting: false };
