if (a.type === 'NEW_MODE' && filterNewMode === false) return null;
if (a.type === 'NEED_QSL' && flow.get('filterNeedQsl', 'file') === false) return null;

// Mode filter
var _modeMap = {CW:'cw',USB:'phone',LSB:'phone',SSB:'phone',AM:'phone',FM:'phone',
                FT8:'data',FT4:'data',RTTY:'data',PSK31:'data',JS8:'data',Data:'data'};
var _modeCat = _modeMap[a.mode] || null;
if (_modeCat === 'cw'    && filterModeCW    === false) return null;
if (_modeCat === 'phone' && filterModePhone === false) return null;
if (_modeCat === 'data'  && filterModeData  === false) return null;

var icons = {NEW_DXCC:'🔴', NEW_BAND:'🔵', NEW_MODE:'🟡', NEED_QSL:'🟣'};
var icon = icons[a.type] || '📻';

var text = icon + ' *' + a.label + '*\n' +
    '📞 `' + a.call + '` — ' + a.entity + '\n' +
    '📻 ' + a.band + ' | ' + a.mode + ' | ' + a.freqMHz + ' MHz\n' +
    '👁 Spotter: ' + a.spotter + '\n' +
    '🕐 ' + a.time;

var token  = flow.get('cfg_tg_token')   || '';
var chatId = flow.get('cfg_tg_chat_id') || '';

msg.url     = 'https://api.telegram.org/bot' + token + '/sendMessage';
msg.method  = 'POST';
msg.headers = {'Content-Type': 'application/json'};
msg.payload = JSON.stringify({
    chat_id:    chatId,
    text:       text,
    parse_mode: 'Markdown'
});

node.status({fill:'blue', shape:'dot', text: a.call + ' → Telegram'});
return msg;

var a = msg.alert;

// Apply same filters as dashboard
var filterBands     = flow.get('filterBands', 'file')   || {};
var filterNewDxcc   = flow.get('filterNewDxcc', 'file');
var filterNewBand   = flow.get('filterNewBand', 'file');
var filterNewMode   = flow.get('filterNewMode', 'file');
var filterModeCW    = flow.get('filterModeCW', 'file');
var filterModePhone = flow.get('filterModePhone', 'file');
var filterModeData  = flow.get('filterModeData', 'file');

// Band filter
if (Object.keys(filterBands).length > 0 && !filterBands[a.band]) return null;

// Alert type filter
if (a.type === 'NEW_DXCC' && filterNewDxcc === false) return null;
if (a.type === 'NEW_BAND' && filterNewBand === false) return null;
if (a.type === 'NEW_MODE' && filterNewMode === false) return null;

// Mode filter
var _modeMap = {CW:'cw',USB:'phone',LSB:'phone',SSB:'phone',AM:'phone',FM:'phone',
                FT8:'data',FT4:'data',RTTY:'data',PSK31:'data',JS8:'data',Data:'data'};
var _modeCat = _modeMap[a.mode] || null;
if (_modeCat === 'cw'    && filterModeCW    === false) return null;
if (_modeCat === 'phone' && filterModePhone === false) return null;
if (_modeCat === 'data'  && filterModeData  === false) return null;

var icons = {NEW_DXCC:'🔴', NEW_BAND:'🔵', NEW_MODE:'🟡'};
var icon = icons[a.type] || '📻';

var text = icon + ' *' + a.label + '*\n' +
    '📞 `' + a.call + '` — ' + a.entity + '\n' +
    '📻 ' + a.band + ' | ' + a.mode + ' | ' + a.freqMHz + ' MHz\n' +
    '👁 Spotter: ' + a.spotter + '\n' +
    '🕐 ' + a.time;

var token  = flow.get('cfg_tg_token')   || '';
var chatId = flow.get('cfg_tg_chat_id') || '';

msg.url     = 'https://api.telegram.org/bot' + token + '/sendMessage';
msg.method  = 'POST';
msg.headers = {'Content-Type': 'application/json'};
msg.payload = JSON.stringify({
    chat_id:    chatId,
    text:       text,
    parse_mode: 'Markdown'
});

node.status({fill:'blue', shape:'dot', text: a.call + ' → Telegram'});
return msg;

var meterToBand = {
    '160':'160M','80':'80M','40':'40M','30':'30M',
    '20':'20M','17':'17M','15':'15M','12':'12M','10':'10M','6':'6M'
};

function fetchURL(target) {
    return new Promise(function(resolve, reject) {
        var u = urlmod.parse(target);
        var options = { hostname:u.hostname, path:u.path, method:'GET',
                        headers:{'User-Agent':'Mozilla/5.0'} };
        var req = https.request(options, function(res) {
            var data = '';
            res.on('data', function(chunk){ data += chunk; });
            res.on('end', function(){ resolve(data); });
        });
        req.on('error', reject);
        req.end();
    });
}

function parseMatrix(raw) {
    raw = raw.trim();
    if (!raw || raw.charAt(0) !== '{') throw new Error('Bad response: ' + raw.substring(0,100));
    var matrix = JSON.parse(raw);
    if (matrix.Error || matrix.error) throw new Error('CL error: ' + (matrix.Error||matrix.error));
    var ew = {};
    Object.keys(matrix).forEach(function(adif) {
        var bands = matrix[adif];
        if (typeof bands !== 'object') return;
        ew[adif] = {};
        Object.keys(bands).forEach(function(mk) {
            var band = meterToBand[mk];
            if (!band || bands[mk] < 1) return;
            var conf = bands[mk] >= 2;
            ew[adif][band] = ew[adif][band] || {confirmed:false,unconfirmed:false};
            if (conf) ew[adif][band].confirmed = true;
            else      ew[adif][band].unconfirmed = true;
        });
    });
    return ew;
}

node.status({fill:'blue', shape:'dot', text:'Fetching all modes...'});

Promise.all([
    fetchURL(msg.mode0url),
    fetchURL(msg.mode1url),
    fetchURL(msg.mode2url),
    fetchURL(msg.mode3url)
]).then(function(results) {
    var ew0 = parseMatrix(results[0]);
    var ew1 = parseMatrix(results[1]);
    var ew2 = parseMatrix(results[2]);
    var ew3 = parseMatrix(results[3]);

    var workedTable = {};
    Object.keys(ew0).forEach(function(adif) {
        Object.keys(ew0[adif]).forEach(function(band) {
            var key = adif + '|' + band;
            workedTable[key] = {dxcc:adif, band:band,
                confirmed:ew0[adif][band].confirmed,
                unconfirmed:ew0[adif][band].unconfirmed};
        });
    });

    var modeWorked = {};
    var allAdifs = {};
    [ew1,ew2,ew3].forEach(function(ew){ Object.keys(ew).forEach(function(a){ allAdifs[a]=1; }); });
    Object.keys(allAdifs).forEach(function(adif) {
        modeWorked[adif] = {
            cw:    !!(ew1[adif] && Object.keys(ew1[adif]).length > 0),
            phone: !!(ew2[adif] && Object.keys(ew2[adif]).length > 0),
            data:  !!(ew3[adif] && Object.keys(ew3[adif]).length > 0)
        };
    });

    var stats = {
        entities:    Object.keys(ew0).length,
        confirmed:   Object.keys(workedTable).filter(function(k){return workedTable[k].confirmed;}).length,
        unconfirmed: Object.keys(workedTable).filter(function(k){return !workedTable[k].confirmed;}).length,
        bandSlots:   Object.keys(workedTable).length
    };


    flow.set('workedTable',    workedTable);
    flow.set('entityWorked',   ew0);
    flow.set('dxccModeWorked', modeWorked);
    flow.set('workedStats',    stats);

    // Also save to file store — survives reboot without re-fetch
    flow.set('workedTable',    workedTable, 'file');
    flow.set('entityWorked',   ew0,         'file');
    flow.set('dxccModeWorked', modeWorked,  'file');
    flow.set('workedStats',    stats,       'file');

    // Write nr_dxcc_seed.json to both locations
    var seed = JSON.stringify({workedTable:workedTable, entityWorked:ew0, dxccModeWorked:modeWorked, stats:stats, updated:new Date().toISOString()});
    var flowsDir = flow.get('cfg_flows_dir') || os.homedir() + '/.node-red';
    var paths = [ flowsDir + '/nr_dxcc_seed.json' ];
    paths.forEach(function(p){
        try { fs.writeFileSync(p, seed); } catch(e) { node.warn('seed write failed: ' + p + ' ' + e.message); }
    });
    node.warn('Seed written to ' + paths.length + ' locations');

    flow.set('dxccReady', true);
    node.status({fill:'green', shape:'dot',
        text: stats.entities + ' entities | ' + stats.confirmed + '✓ ' + stats.unconfirmed + '✗ | modes OK'});
    node.send({payload: stats});
}).catch(function(err) {
    node.error('Club Log fetch failed: ' + err.message);
    node.status({fill:'red', shape:'dot', text:'Club Log unreachable — using seed'});
    // Fall back to seed data if already loaded by bootstrap
    var existing = flow.get('workedTable');
    if (existing && Object.keys(existing).length > 10) {
        flow.set('dxccReady', true);
        node.warn('Club Log unreachable — falling back to seed data, alerts enabled');
        node.send({payload: flow.get('workedStats') || {entities:0,confirmed:0,unconfirmed:0,bandSlots:0}});
    } else {
        node.warn('Club Log unreachable and no seed data — alerts remain paused');
    }
});
return;

// websocket in delivers msg.payload as the raw text frame.
// Binary frames (RCU LCD mirror) arrive as Buffers; we skip those.
if (Buffer.isBuffer(msg.payload)) return null;
if (typeof msg.payload !== 'string') return null;

let d;
try { d = JSON.parse(msg.payload); }
catch (e) { return null; }

msg.payload = d;

// Route by message type.
// Output 1: amplifier state
// Output 2: heartbeat (serial up/down + client count)
// Output 3: power-action result
if (d.heartbeat)         return [null, msg, null];
if (d.power_result)      return [null, null, msg];
if (d.op_status !== undefined) return [msg, null, null];
return null;

// Convert the server's state JSON to the flat shape the SPE Panel
// UI Template expects (mode, rxtx, band, pwr, atuswr, ... etc.).
const d = msg.payload;
if (!d) return null;

const pwrMap    = { L: 'Low',    M: 'Middle', H: 'Maximum' };
const pwrMaxMap = { L: 500,      M: 1000,     H: 1500      };
// 2K-FA full-scale bumps to 2000W if you have one.
if (d.model_id === '20K') {
  pwrMaxMap.L = 700; pwrMaxMap.M = 1400; pwrMaxMap.H = 2000;
}

msg.payload = {
  model:     d.model_id || '—',
  mode:      d.op_status === 'Stby' ? 'Standby' : 'Operate',
  rxtx:      d.tx_status === 'TX'   ? 'TRANSMIT' : 'RECEIVE',
  bank:      '—',                              // not exposed by server
  input:     d.input    || '—',
  band:      (d.band    || '—').toUpperCase(),
  txant:     d.tx_antenna || '—',
  rxant:     '—',                              // not exposed by server
  pwrlvl:    pwrMap[d.p_level] || d.p_level || '—',
  pwr:       parseFloat(d.p_out)   || 0,
  pwrMax:    pwrMaxMap[d.p_level]  || 1500,
  atuswr:    parseFloat(d.swr)     || 1,
  antswr:    parseFloat(d.aswr)    || 1,
  vpa:       parseFloat(d.voltage) || 0,
  ipa:       parseFloat(d.drain)   || 0,
  tempUpper: parseFloat(d.pa_temp)          || 0,
  tempLower: parseFloat(d.pa_temp_lower)    || 0,
  tempComb:  parseFloat(d.pa_temp_combiner) || 0,
  warnings:  d.warnings && d.warnings.trim() ? d.warnings : 'No Warnings',
  alarms:    d.error    && d.error.trim()   ? d.error    : 'No Alarms',
  usb:       true,
  sync:      true
};
return msg;

// Push the server's serial-link state to the USB chip on the panel.
// Partial payload — the UI Template only updates fields that are
// !== undefined, so the rest of the dashboard stays as it was.
const d = msg.payload;
if (!d) return null;
msg.payload = {
  usb: d.serial === 'up',
  sync: d.serial === 'up'
};
return msg;

// Map dashboard button payloads onto the bare command names that
// spe-remote's WebSocket handler accepts.
const map = {
  MODE: 'oper',
  TUNE: 'tune',
  INPUT: 'input',
  ANTENNA: 'antenna',
  PWRLVL: 'power_level',
  BL_ON: 'backlight_on',
  BL_OFF: 'backlight_off',
  L_MINUS: 'l_minus',
  L_PLUS: 'l_plus',
  C_MINUS: 'c_minus',
  C_PLUS: 'c_plus',
  LEFT: 'left',
  RIGHT: 'right',
  SET: 'set',
  DISPLAY: 'display',
  BAND_MINUS: 'band_dn',
  BAND_PLUS: 'band_up',
  OFF_SPE: 'power_off',
  ON_SPE: 'power_on'
};
const cmd = map[msg.payload];
if (!cmd) {
  // Unknown / not-supported-via-WS button (e.g. legacy BANK / LOGGING
  // / FAN_*). Drop silently rather than spam the server.
  return null;
}
msg.payload = cmd;
return msg;
